<template>
  <v-dialog :model-value="dialog" width="25%">
    <v-card class="mx-auto card" width="100%">
      <v-toolbar dark color="#624fc6" class="mb-2">
        <v-btn
          icon
          fab
          color="#ffffff"
          x-small
          @click="$emit('popClose')"
          class="mr-1"
        >
          <Icon
            class="icon_download"
            icon="ic:outline-close"
            color="#ffffff"
            width="25"
          />
        </v-btn>

        <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
          <h4 style="font-family: 'Cairo', sans-serif">
            عدد العناصر المسترجعه
          </h4>
        </v-toolbar-title>
      </v-toolbar>
      <v-card-title class="d-flex justify-stert"
        ><h4 style="color: #50535b">
          حدد الكمية المسترجعه من هذا العنصر
        </h4></v-card-title
      >
      <v-card-text class="mt-2">
        <v-col cols="12" sm="12" md="12" lg="12">
          <Input
            v-model="quantity"
            @update-value="quantity = $event"
            autocomplete="quantity"
            type="Number"
            label="عدد العناصر المسترجعه"
            :rules="AllRulse"
            :min="1"
            :max="maxQuantity"
          />
        </v-col>
      </v-card-text>
      <v-card-actions class="mt-5 pb-5">
        <v-btn
          size="large"
          @click="retrieve_item"
          color="#624fc6"
          class="px-16 mx-auto border-btn"
          elevation="4"
          variant="flat"
        >
          <h4 style="color: white; font-size: 17px">استرجاع</h4>
        </v-btn>
      </v-card-actions>
    </v-card>
  </v-dialog>
</template>
<script setup>
import { ref, defineEmits } from "vue";
import Input from "@/components/layout/Input.vue";
import { useSnackbarStore } from "@/stores/snackbar";

const quantity = ref(1);
const emit = defineEmits(["retrieveQuantity"]);
const AllRulse = [(value) => !!value || "هذا الحقل مطلوب"];

const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  maxQuantity: {
    type: Number,
    required: true,
  },
});

function retrieve_item() {
  if (quantity.value <= props.maxQuantity) {
    emit("popClose");
    emit("retrieveQuantity", quantity.value);
  } else {
    const snackbar = useSnackbarStore();

    snackbar.showMessage({
      color: "#B71C1C",
      icon: "ri:close-circle-fill",
      text: "الكمية التي ادخلتها اكبر من الكمية المتوفره",
    });
  }
}
</script>
<style scoped>
.card {
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
}
</style>
